public class Product {
    String name;
    double price;
    int quantity;

    // Constructor: parameters are also named name, price, quantity
    // Use 'this' to assign parameters to instance fields
    Product(String name, double price, int quantity) {
        // Without 'this', 'name = name' assigns the parameter to itself
        // With 'this.name = name', left side is the field, right side is the parameter
    }

    void display() {
        System.out.println("Product: " + name + " | Price: $" + price + " | Qty: " + quantity);
    }

    public static void main(String[] args) {
        Product p1 = new Product("Laptop", 999.99, 5);
        Product p2 = new Product("Mouse", 29.99, 20);
        p1.display();
        p2.display();
    }
}

public class Circle {
    double radius;
    String color;

    // Primary constructor: accepts both radius and color
    Circle(double radius, String color) {
        this.radius = radius;
        this.color = color;
        System.out.println("Circle created: radius=" + radius + ", color=" + color);
    }

    // Secondary constructor: accepts only radius, delegates to primary with default color "White"
    Circle(double radius) {
        // Use this() to call the primary constructor
    }

    public static void main(String[] args) {
        Circle c1 = new Circle(5.0, "Red");
        Circle c2 = new Circle(3.0);         // should use default color "White"
    }
}

public class QueryBuilder {
    private String table = "";
    private String condition = "";
    private int limit = 100;

    // setTable(String table): assigns table, returns this

    // setCondition(String condition): assigns condition, returns this

    // setLimit(int limit): assigns limit, returns this

    public String build() {
        return "SELECT * FROM " + table +
               (condition.isEmpty() ? "" : " WHERE " + condition) +
               " LIMIT " + limit;
    }

    public static void main(String[] args) {
        String query = new QueryBuilder()
            .setTable("users")
            .setCondition("age > 18")
            .setLimit(50)
            .build();

        System.out.println(query);
    }
}
